    ['Fit for a Prince'] = {
        id = 106,
        start_npc = 'Halver',
        start_zone = 'Chateau d\'Oraguille',
        start_pos = 'I-9',
        description = 'You are to find a suitable bride for Prince Trion based on the requirements explained to you.',
        reward = 'Castor\'s Ring \nPollux\'s Ring',
        fame = 'San d\'Oria',
        fame_level = '3',
        title = 'Royal Wedding Planner',
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Halver for a cutscene.  During the cutscene, you are told the description of the type of female Prince Trion is attracted to.\n2. Find a player who matches the description and make a party with them.  Then return to Halver while in the same party as the match.\n3. Both players must speak to Halver, and each one will receive the same cutscene.\n   - The player who started this quest gains the title of Royal Wedding Planner as well as Castor\'s Ring.\n   - The player who matches the description will gain the title of Consort Candidate and Pollux\'s Ring.\nThe rings can be synthesized with a Wind Crystal, and can also be signed with a Cyclone Crystal. Doing so with either will also remove the  and  attributes, and the rings can be traded to another person, acting like a Wedding Ring.',
        notes = '1. This quest can be abandoned and re-accepted every minute without zoning.\n   - To be given a different female description, you must accept and then cancel the quest.\n   - The quest is reset every minute at XX:XX:00 earth time, not when you actually cancel the quest.\n2. Having a female character in the party does NOT force Halver to ask for that character! It is still random!',
    },
    ['Flyers for Regine'] = {
