    ['Over the Hills and Far Away'] = {
        id = 112,
        start_npc = 'Antreneau',
        start_zone = 'Port San d\'Oria',
        start_pos = 'G-7',
        description = 'Antreneau\'s Uncle Louverance set out on a journey to cross the Uleguerand Range quite some time ago. Antreneau tells you that the other side of the mountains can be reached through a cave found on the slopes of Thousandfall Ridge...',
        reward = 'Map of the Uleguerand Range\n2,000 Experience Points\n2,000 Gil',
        fame = 'San d\'Oria',
        fame_level = '8',
        title = nil,
        repeatable = nil,
        previous = {
            'A Squire\'s Test II',
            'The Medicine Woman',
        },
        next = nil,
        requirements = {
            {name = 'Moblin Hotrok', count = 1},
        },
        walkthrough = '1. First you need to to go to the second floor of the house at (G-7) in Southern San d\'Oria and read the diary there until you have read up to Page 4.\n2. Speak to Antreneau, Port San d\'Oria (G-7) to flag the quest.\n3. Head to Oldton Movalpolos and kill Moblin Ashman and Moblin Gurneyman until they drop a Moblin Hotrok. Alternately, you can go to Newton Movalpolos and kill Moblin Groundman.\n4. Head to Uleguerand Range and climb to the top where Jormungand spawns.\n5. At (F-9) you will find a slope leading all the way down to the entrance of the zone.\n6. Fall down the Southern Slope (the one you see as soon as you zone) and aim for the ledge on your left.\n   - If you miss the ledge you will have to climb up the mountain and try again.\n7. Once on the ledge head inside the hole and examine the ???.\n8. Trade the Moblin Hotrok to the ??? to complete this quest.',
        notes = nil,
    },
    ['Peace for the Spirit'] = {
        id = 86,
        start_npc = 'Curilla',
        start_zone = 'Chateau d\'Oraguille',
        start_pos = 'I-9',
        description = 'The spirit of Curilla\'s father Rainemard seems to be trying to say something.',
        reward = 'Warlock\'s Chapeau',
        fame = 'San d\'Oria',
        fame_level = '1',
        title = 'Paragon of Red Mage Excellence',
        repeatable = 'No',
        previous = {'Enveloped in Darkness'},
        next = nil,
        requirements = {
            {name = 'Antique Coin', count = 1},
            {name = 'Nail Puller', count = 1},
        },
        walkthrough = '1. As a Red Mage, Talk to Curilla in Chateau d\'Oraguille at (I-9) to start this quest.\n   - Note: You don\'t have to be RDM for the remainder of this quest.\n2. Head to Southern San d\'Oria, find Sharzalion at (K-6) in the Lion Springs Tavern and speak to him.\n3. Kill Miser Murphy in Fei\'Yin for an Antique Coin.\n   - He will pop at (H-8) on map1 if the quest is active.\n   - 10 minute respawn time\n4. Trade the coin to the Dry Fountain at (H-8) for a cutscene.\n5. Head to Southern San d\'Oria and speak to Sharzalion and then speak with Daggao who is in the bar as well.\n6. Go to Garlaige Citadel (G-8) behind the first banishing gate (map 2) click the Oaken Box in the first room to the left. This will spawn the Guardian Statue.\n   - If you get the message "Something feels wrong, but nothing happens.", click off Sneak.\n7. Kill him for a Nail Puller.\n8. Trade the Nail Puller to the same Oaken box for a Cutscene.\n9. Zone into Northern San d\'Oria for a Cutscene and Warlock\'s Chapeau.',
        notes = nil,
    },
    ['Pieuje\'s Decision'] = {
        id = 89,
        start_npc = 'Pieuje',
        start_zone = 'Chateau d\'Oraguille',
        start_pos = 'H-8',
        description = 'Once you\'ve found a Tavnazia Bell in Eldieme Necropolis, journey to Fei\'Yin and commence the battle against the undead.',
        reward = 'Healer\'s Bliaut',
        fame = 'San d\'Oria',
        fame_level = '1',
        title = 'Paragon of White Mage Excellence',
        repeatable = 'No',
        previous = {'Prelude of Black and White'},
        next = nil,
        requirements = {
            {name = 'Tavnazia Bell', count = 1},
            {name = 'Tavnazian Mask', count = 1},
        },
        walkthrough = '1. Open Door: Prince Regent\'s Rm in Chateau d\'Oraguille at (H-8) to start this quest.\nYou can continue as any job at this point.\n2. Go to Eldieme Necropolis and kill Dark Stalkers until a Tavnazia Bell drops.\n   - There are 4 spawn points near the Hume Bones from the drop at (G-8) in the center of map 2.\n   - There are also 4 spawns at C and B drops of map 1.\n3. Travel to Fei\'Yin and zone in for a cutscene.\n   - Warping to the Home Point will trigger the cutscene\n4. Locate the ??? at (G-8) on Map 1. Trade the Tavnazia Bell to the ??? to pop Altedour I Tavnazia.  Be warned he is one of the strongest AF NMs out there.  He will drop a Tavnazian Mask.\n   - If more than one character is doing this quest, you will have to wait a few minutes before popping the NM again. You will get "You find nothing." for a few minutes when trying to trade the Tavnazia Bell.\n5. Trade the Tavnazian Mask to Narcheral in the Cathedral upstairs in Northern San d\'Oria at (M-6) to receive your Healer\'s Bliaut.',
        notes = nil,
    },
    ['Prelude of Black and White'] = {
        id = 88,
        start_npc = 'Pieuje',
        start_zone = 'Chateau d\'Oraguille',
        start_pos = 'H-8',
        description = 'White mages of renown will be given a blessed item for the war against the undead. But first, they must bring Yagudo holy water to prove their worth.',
        reward = 'Healer\'s Duckbills',
        fame = 'San d\'Oria',
        fame_level = '1',
        title = nil,
        repeatable = 'No',
        previous = {'Messenger from Beyond'},
        next = {
            'Pieuje\'s Decision',
            'Borghertz\'s Healing Hands',
        },
        requirements = {
            {name = 'Moccasins', count = 1},
            {name = 'Yagudo Holy Water', count = 1},
        },
        walkthrough = '1. As a White Mage, examine the Door: Prince Regent\'s Rm in Chateau d\'Oraguille at (H-8) to start this quest.\n   - You must be able to access Chateau d\'Oraguille.\n     - Players from San d\'Oria must be rank 2, but players from other nations must be on Bastok / Windurst Mission 2-3.\n2. Go to Castle Oztroja or Castle Zvahl Keep and kill Yagudo Abbots until a Yagudo Holy Water drops.\n3. Yagudo Abbots spawn behind the brass door at (G-8) on map 3.\n   - The combination to these levers can be found behind the secret door at (I-10) on the same map.\n   - Yagudo Abbots located at (G-9) & (G-10) on map 2 in Castle Zvahl Keep can also drop Yagudo Holy Water. Although fewer of them spawn in this zone, they are 1-7 levels lower than Yagudo Abbots in Castle Oztroja.\n4. Find a pair of Moccasins\n   - Purchasable from the Auction House\n   - Dropped from Multiple Enemies\n   - Synthesized from a level 59 Leathercraft synth\n5. Take the pair of Moccasins and the Yagudo Holy Water to Narcheral (M-6) in Northern San d\'Oria to complete this quest and obtain your Healer\'s Duckbills.',
        notes = nil,
    },
    ['Rosel the Armorer'] = {
        id = 2,
        start_npc = 'Rosel',
        start_zone = 'Southern San d\'Oria',
        start_pos = 'K-8',
        description = 'Deliver the Rreceipt for the prince\'s cloak to the chateau guards.',
        reward = '100-200 gil',
        fame = 'San d\'Oria',
        fame_level = '1',
        title = 'Entrance Denied',
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Upon speaking to Rosel in Southern San d\'Oria, he will ask you to deliver [Key Item] Receipt for the prince to either Prince Pieuje or Prince Trion in Chateau d\'Oraguille. The chosen prince is random, but if you forget which was chosen you can return to Rosel for a reminder.\n2. Leave Rosel\'s Armour Shop and head west into Victory Square. Head north through Victory Arch into Northern San d\'Oria. Proceed straight north towards Chateau d\'Oraguille.\n3. Look for the NPC Guilerme, a guard standing near the bridge into the Chateau. Upon speaking to him, he will take the receipt but is unable to read the intended recipient. After you tell him which prince, Pieuje or Trion, he will run into the Chateau to deliver the receipt.\n4. After the cutscene with Guilerme is complete, return to Rosel for your reward. If Guilerme was told the right prince, you will receive 200 gil for a reward. However, if the wrong prince was chosen, you will only receive 100 gil.',
        notes = nil,
    },
    ['Sharpening the Sword'] = {
        id = 90,
        start_npc = 'Ailbeche',
        start_zone = 'Northern San d\'Oria',
        start_pos = 'J-8',
        description = 'The boy needs a whetstone to sharpen an old blade. Find one for him in Ordelle\'s Caves.',
        reward = 'Honor Sword',
        fame = 'San d\'Oria',
        fame_level = nil,
        title = nil,
        repeatable = 'Yes',
        previous = {
            'A Knight\'s Test',
            'Father and Son',
        },
        next = {'A Boy\'s Dream'},
        requirements = {
            {name = '[Key Item] Ordelle whetstone', count = 1},
        },
        walkthrough = '1. In order to start this quest, it\'s necessary to trade back the fishing rod to Ailbeche from the previous quest Father and Son.\n2. Speak with Ailbeche near Home Point #2 to begin the quest.\n   - He will ask you for an Ordelle whetstone.\n3. Talk to Sobane in (D-6) of Southern San d\'Oria.\n   - Be sure to talk to her twice if you get a cutscene the first time.\n4. Enter Ordelle\'s Caves from the entrance in La Theine Plateau position (F-7). This will put you on map 2.\n   - Taking the survival guide to Ordelle\'s Caves is the fastest route.\n5. Take the first left and walk towards (I-6) on map 2 on to use exit B which will put you on map 1. Walk towards (H-9) exit D, which will put you back on map 2 again.\n6. Examine the Stalagmite in the circular room at (H-10) on map 2 to pop the NM Polevik an Earth Elemental.\n   - Be careful not to fall down the hole in this room.\n7. Defeat the Polevik, then examine the Stalagmite again to obtain the key item: Ordelle whetstone.\n8. Return to Ailbeche to end the quest and receive your reward.',
        notes = nil,
    },
    ['Signed in Blood'] = {
        id = 108,
        start_npc = 'Sobane',
        start_zone = 'Southern San d\'Oria',
        start_pos = 'D-6',
        description = 'Sobane has heard some disturbing news from her husband, the head royal chef. She wishes to make a request concerning that tale, but first requires you to bring a "cathedral tapestry" to prove your integrity.',
        reward = 'Cunning Earring \n3,500 gil',
        fame = 'San d\'Oria',
        fame_level = '3',
        title = nil,
        repeatable = nil,
        previous = nil,
        next = {'Tea with a Tonberry?'},
        requirements = {
            {name = 'Cathedral Tapestry', count = 1},
            {name = '[Key Item] Torn-out pages', count = 1},
        },
        walkthrough = '1. Speak to Sobane who will request you bring her a Cathedral Tapestry.\n   - Cathedral Tapestry drops off Orcish Fighters in Fort Ghelsba or the Yughott Grotto.\n2. Trade the Cathedral Tapestry to Sobane.\n3. Travel to Selbina and speak to Abelard (G-9).\n4. Head to Ordelle\'s Caves obtain an Ordelle Chest Key off the monsters inside.\n   - Certain monsters in the cave drop the key. To reach that area, take path D on map 1, drop into the southeastern hole depicted on map 2, then take path E.\n   - The high-level mobs Buds Bunny, Swagger Spruce, Targe Beetle do not aggro.\n5. Use the key on a chest inside to receive [Key Item] Torn-out pages.\n6. Return to Abelard.\n7. Speak to Sobane to complete this quest.',
        notes = nil,
    },
