    ['Sorcery of the North'] = {
        id = 83,
        start_npc = 'Eperdur',
        start_zone = 'Northern San d\'Oria',
        start_pos = 'M-7',
        description = 'An ancient tome of magic is lost. Journey to Fei\'Yin and find another to replace it.',
        reward = 'Scroll of Teleport-Vahzl',
        fame = 'San d\'Oria',
        fame_level = '4',
        title = nil,
        repeatable = nil,
        previous = {'Healing the Land'},
        next = nil,
        requirements = {
            {name = 'Fei\'Yin Chest Key', count = 1},
            {name = '[Key Item] Fei\'Yin magic tome', count = 1},
        },
        walkthrough = '1. Zone after completing Healing the Land to begin this quest.\n2. Speak to Eperdur in Northern San d\'Oria (M-7) second level of the Cathedral.\n3. Obtain a Fei\'Yin Chest Key by defeating Shadows, Underworld Bats and Ore Golems in that area.\n4. Open a treasure chest using either the key or Thief\'s Tools to obtain the [Key Item] Fei\'Yin magic tome.\n5. Return to Eperdur to receive your reward.',
        notes = nil,
    },
    ['Souls in Shadow'] = {
        id = 99,
        start_npc = 'Novalmauge',
        start_zone = 'Bostaunieux Oubliette',
        start_pos = 'G-8',
        description = 'Lift the curse on the scythe Novalmauge has given you and gain a new weapon technique.',
        reward = 'Spiral Hell weapon skill',
        fame = 'San d\'Oria',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. You cannot start this quest if you have another Weapon Skill Quest active. You must return to the person that gave said quest and quit it to start another.\n2. Speaking with Novalmauge will grant you the key item [Key Item] Weapons Training Guide as well as the Scythe of Trials. You will need to break the latent on the Scythe of Trials before completing the rest of the quest.\n3. Breaking the Latent\n      - Trade the Scythe of Trials back to Novalmauge. This will give you the key item [Key Item] Map to the Annals of Truth. You will be instructed to travel to the Den of Rancor.\n      - Unity Warp 128 to Den of Rancor is closest. You\'ll start on the ledge at (G-12), drop down the east side and walk a short distance southeast to (I-13) where you\'ll find the ???.\n      - You can substantially cut down your journey by taking Den of Rancor Home Point #1 if you have already unlocked it. This will place you on the same map as the ??? described below, letting you skip the intermediate steps given in this guide.\n4. Take Silent Oil and Prism Powder with you and head to the Temple of Uggalepih. Make sure that you either have a [Key Item] Paintbrush of Souls or someone in your party has one.\n5. Once inside the Temple, head to the first intersection and go south. At the next T-intersection, head north to another T-intersection and go north again. This will zone you into Yhoator Jungle; you will then need to head west and south directly back into the Temple of Uggalepih.\n6. This time, when you enter the Temple, you will head to the first intersection and go west. Go through the Wooden Gate and continue south until you reach a T-intersection; head east here. Defeat the Temple Guardian that protects the Granite Door and head east into the large circular room. Take the hallway in the northeastern part of this room at (J-9). Use the [Key Item] Paintbrush of Souls to open the Granite Door at (I-7) and head into the Den of Rancor.\n7. Inside the Den, head south and turn immediately to the east when the room opens up. Take the north tunnel and go east at the intersection. Head down this tunnel until it opens up into a large room. Go south through this room to (I-13); this is where the ??? is to spawn the NM.\n8. This fight is against Mokumokuren, a hecteyes. Once you kill it, re-examine the ??? to receive the key item [Key Item] Annals of Truth.\n9. Go back and speak with Novalmauge to receive your reward.',
        notes = nil,
    },
    ['Spice Gals'] = {
        id = 110,
        start_npc = 'Rouva',
        start_zone = 'Southern San d\'Oria,',
        start_pos = 'I-8',
        description = 'Rouva needs a sprig of the rare Rivernewort to spruce up her succulent suppers.',
        reward = 'Page from Miratete\'s Memoirs',
        fame = 'San d\'Oria',
        fame_level = '1',
        title = nil,
        repeatable = 'Yes',
        previous = nil,
        next = {'Secrets of Ovens Lost'},
        requirements = nil,
        walkthrough = 'Talk to Rouva on the West side of Victory Square (I-8) to begin the quest. She will ask you to bring her a sprig of Rivernewort.\n1. The Rivernewort key item can be found at a ??? located in either Riverne - Site #B01 or Riverne - Site #A01. To get to either you will require Giant Scale(s), or the Home Point Warps, to teleport through the Unstable Displacements.\n   - Riverne - Site #A01: The ??? is found on the island at (E-8) containing the zone to Monarch Linn. Two Giant Scales are required. (The Home Point warp places you at (I-9)).\n   - Riverne - Site #B01: The ??? is found on the island at (E-7), just before the final Stable Displacement heading towards Monarch Linn island. One Giant Scale, or the Home Point warp, is required.\n2. Once you have acquired the Rivernewort, return to Rouva for your reward; a Page from Miratete\'s Memoirs.',
        notes = nil,
    },
