    ['Tea with a Tonberry?'] = {
        id = 109,
        start_npc = 'Sobane',
        start_zone = 'Southern San d\'Oria',
        start_pos = 'D-6',
        description = 'According to Sobane\'s husband Ondieumais, the count who owns the Carpenters\' Landing territory is being threatened. Find a way to communicate with the Tonberries of Carpenters\' Landing and discover who is making these threats.',
        reward = 'Willpower Torque',
        fame = 'San d\'Oria',
        fame_level = '4',
        title = 'Talks with Tonberries',
        repeatable = nil,
        previous = {'Signed in Blood'},
        next = nil,
        requirements = {
            {name = 'Attohwa Ginseng', count = 1},
            {name = 'Treasury Gold', count = 1},
        },
        walkthrough = '1. Speak to Sobane to begin this quest.\n   - You will need to zone after finishing Signed in Blood.\n2. You will need a Attohwa Ginseng for the next part of the quest.\n   - Attohwa Ginseng drops off Gallinippers, Ogreflys, and Monarch Ogreflys in Attohwa Chasm.\n3. Enter Carpenters\' Landing by taking the entrance from Jugner Forest (J-8).\n   - The Carpenters\' Landing Survival Guide will put you right next to Anguenet.\n4. Speak to Anguenet (J-10) and trade him the Attohwa Ginseng.  In return, he will give you a [Key Item] Tonberry blackboard.\n5. Purchase a ticket and board a barge headed for Central Landing via Emfea Way.\n   - This barge leaves at 00:50 every game day, from the docks next to Anguenet.\n6. On the ship, you will find Riche.  Speak to him and ask him all five questions.  After you ask him all the questions, he will take the [Key Item] Tonberry blackboard from you.\n7. Head to Fei\'Yin and kill the Shadows there until they drop Treasury Gold.\n   - You only need one per party.\n8. Go to Davoi and trade the Treasury Gold to the ??? (J-11) to spawn the NM Hematic Cyst.\n9. After the Hematic Cyst is defeated, check the ??? again for a cutscene.\n10. Return to Sobane for your reward.',
        notes = nil,
    },
    ['The Brugaire Consortium'] = {
