    ['To Cure a Cough'] = {
        id = 20,
        start_npc = 'Nenne',
        start_zone = 'Southern San d\'Oria',
        start_pos = 'F-6',
        description = 'Bring Amaura some thyme moss, and she\'ll concoct a brew with curative powers.',
        reward = '3,000 gil',
        fame = 'San d\'Oria',
        fame_level = '3',
        title = 'A Moss Kind Person',
        repeatable = 'No',
        previous = {'The Medicine Woman'},
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Nenne, Southern San d\'Oria (F-6)\n      - Important note: this quest will not immediately appear on your quest log until the actual \'item hunt\' portion of the quest has been activated (see below).\n2. Once you have heard Nenne\'s story, go into the first house on Watchdog Alley (G-7) and go upstairs into a bedroom and on the table there is a ???. Click this and the option to read a diary will appear. Finish reading the diary entirely (continue paging through) to continue to the next portion.\n3. Speak to Amaura (G-6) who will ask for Thyme moss.\n   - To get the moss, you need to examine a ??? at (F-9) in Davoi.\n4. Return the moss to Amaura who will give you Cough medicine.\n5. Speak to Nenne who will give you a Scroll of treasure as your reward.\n6. The scroll leads you to the signpost at (H-6) in East Ronfaure.\n7. Examine the signpost for 3,000 gil.',
        notes = nil,
    },
    ['Trial by Ice'] = {
        id = 59,
        start_npc = 'Gulmama',
        start_zone = 'Northern San d\'Oria',
        start_pos = 'E-7',
        description = 'Ring the tuning fork of ice upon the protocrystal in Fei\'Yin. A path will open to the trial that awaits.',
        reward = 'Shiva (Avatar)\n10,000 Gil\nShiva\'s Claws\nIce Belt\nIce Ring\nRust \'B\' Gone',
        fame = 'San d\'Oria',
        fame_level = '6',
        title = 'Heir of the Great Ice',
        repeatable = 'Yes',
        previous = nil,
        next = {
            'The Moonlit Path',
            'Mama Mia',
        },
        requirements = nil,
        walkthrough = '1. Speak with Gulmama to obtain quest. If you are positive that you have the required fame but she is not allowing you to undertake this quest, continue speaking with her until her text changes. Once you have received the key item: Tuning fork of ice, you can now safely undertake the quest.\n2. Travel to Beaucedine Glacier and enter the ruins of Fei\'Yin at (J-4). In Fei\'Yin (Map A) travel to (G-9) and go down the stairs to the second map. In the basement (Map B) travel to (I-5) to find the entrance to the Cloister of Frost.\n   - Preferably, home point to Fei\'Yin #2. If you don\'t have it yet, make sure to grab it on the way.\n3. Defeat Shiva Prime to receive the key item: Whisper of frost\n4. Return to Gulmama with the whisper and she will provide several reward options including the ability to summon Shiva.',
        notes = '1. Up to 6 party members can enter the arena.\n2. Each party member must have their own Tuning fork of ice\n3. Time limit is 30 minutes\n4. You can only select 1 of the rewards Gulmama offers at any time\n5. You may repeat this quest once per Earth day.\n6. You can save yourself a lot of time traveling to the Cloister of Frost by using the Mini Fork of Ice given by the quest Trial-Size Trial by Ice.  You must be on Summoner as your main job, and obtain the Mini Tuning Fork from Castilchat, trade the fork back to Castilchat, but enter the Protocrystal normally.  So long as you do not clear the level 20 version of the BC, you may warp to the Cloister of Frost as many times as you wish.\n7. You may also choose to retain the whisper in order to complete the requirements for this quest: The Moonlit Path',
    },
    ['Trial-Size Trial by Ice'] = {
        id = 107,
        start_npc = 'Castilchat',
        start_zone = 'Northern San d\'Oria',
        start_pos = 'E-7',
        description = 'The Rhinostery has developed a new "mini" tuning fork of ice. Ringing it upon the protocrystal in Fei\'Yin will open the path to a one-on-one battle with the beast that awaits inside. However, only summoners are allowed to take up this challenge.',
        reward = 'Instant Warp',
        fame = 'San d\'Oria',
        fame_level = '2',
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak with Castilchat in Northern San d\'Oria (E-7) to begin quest and obtain a Mini Tuning Fork of Ice.\n2. You may prepare for the upcoming battle and whenever you are ready, trade Castilchat the tuning fork to be transported to the arena.\n3. Trade the fork to the Ice Protocrystal to enter the fighting arena.\n4. Defeat Shiva Prime to complete quest.',
        notes = '1. Only Carbuncle may be used for this battle.\n   - Siren can also be used but it seems unintended.\n2. Use pet food (e.g. Grape Daifuku) and bring along a few Dawn Mulsum and juices if you don\'t want to use Astral Flow\n3. You must face this challenge alone.\n4. You may buff outside of the fight. Level cap will not dispel them.\n5. There is a 15 minutes time limit on the arena.\n6. Warning You may re-obtain the Mini Tuning Fork from the starting NPC at any point if you desire and repeat the fight, but the NPC will no longer teleport you to the Cloister.\n   - These were historically prized for their teleportation abilities, but Home Point warps have largely supplanted them.',
    },
